// First page: sort by a tiebreaker-inclusive key so order is total
GET /products/_search
{
  "size": 20,
  "query": { "match": { "name": "running shoes" } },
  "sort": [ { "_score": "desc" }, { "_id": "asc" } ]
}

// Next page: pass the sort values of the LAST hit from the previous page.
// No offset -> constant cost regardless of depth.
GET /products/_search
{
  "size": 20,
  "query": { "match": { "name": "running shoes" } },
  "sort": [ { "_score": "desc" }, { "_id": "asc" } ],
  "search_after": [ 8.42137, "prod-10420" ]
}

challenges.solutionCode:
GET /products/_search
{
  "query": {
    "bool": {
      "must": [
        { "match": { "name": { "query": "lightweight running shoes", "boost": 2 } } }
      ],
      "should": [
        { "match": { "description": "lightweight running shoes" } }
      ],
      "filter": [
        { "term":  { "in_stock": true } },
        { "terms": { "brand": [ "nike", "asics" ] } },
        { "range": { "price": { "gte": 20, "lte": 150 } } }
      ],
      "must_not": [
        { "term": { "category": "clearance" } }
      ]
    }
  }
}
